#include <bits/stdc++.h>
using namespace std;
const int maxn=5005;
int n,a[maxn],dp[maxn],cnt[maxn],ans1,ans2;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	for(int i=1; i<=n; i++) {
		dp[i]=1;
		for(int j=1; j<i; j++) {
			if(a[i]<a[j]) {
				dp[i]=max(dp[i],dp[j]+1);
			}
		}
		ans1=max(ans1,dp[i]);
	}
	for(int i=1; i<=n; i++) {
		if(dp[i]==1) {
			cnt[i]=1;
		}
		for(int j=1; j<i; j++) {
			if(dp[i]==dp[j]+1&&a[i]<a[j]) {
				cnt[i]+=cnt[j];
			} else if(dp[i]==dp[j]&&a[i]==a[j]) {
				cnt[i]=0;
			}
		}
		if(dp[i]==ans1) {
			ans2+=cnt[i];
		}
	}
	cout<<ans1<<" "<<ans2;
	return 0;
}
